import xml.etree.ElementTree as ET
from .exceptions import SAMLValidationError

SAML_PROTOCOL_NS = 'urn:oasis:names:tc:SAML:2.0:protocol'
SAML_ASSERTION_NS = 'urn:oasis:names:tc:SAML:2.0:assertion'
XMLDSIG_NS = 'http://www.w3.org/2000/09/xmldsig#'

NAMESPACES = {
    'samlp': SAML_PROTOCOL_NS,
    'saml': SAML_ASSERTION_NS,
    'ds': XMLDSIG_NS,
}


class SAMLXMLValidator:
    """Validates SAML XML structure."""

    REQUIRED_RESPONSE_ATTRIBUTES = ['ID', 'Version', 'IssueInstant']
    REQUIRED_ASSERTION_ATTRIBUTES = ['ID', 'Version', 'IssueInstant']
    SUPPORTED_VERSION = '2.0'
    MAX_XML_SIZE = 500 * 1024  # 500KB max

    def __init__(self, xml_string):
        if isinstance(xml_string, bytes):
            self.xml_string = xml_string
        else:
            self.xml_string = xml_string.encode('utf-8')
        self.root = None
        self.errors = []

    def validate(self):
        """Run all validations and return (is_valid, errors)."""
        self.errors = []

        self._validate_size()
        if self.errors:
            return False, self.errors

        self._parse_xml()
        if self.errors:
            return False, self.errors

        self._validate_root_element()
        if self.errors:
            return False, self.errors

        self._validate_version()
        self._validate_response_attributes()
        self._validate_status()
        self._validate_assertion_structure()
        self._validate_no_dtd()

        return len(self.errors) == 0, self.errors

    def _validate_size(self):
        if len(self.xml_string) > self.MAX_XML_SIZE:
            self.errors.append(
                f"XML document exceeds maximum size of {self.MAX_XML_SIZE} bytes"
            )

    def _parse_xml(self):
        try:
            # Use defusedxml-style parsing to prevent XXE attacks
            # In production, use defusedxml library
            self.root = ET.fromstring(self.xml_string)
        except ET.ParseError as e:
            self.errors.append(f"XML parsing error: {str(e)}")

    def _validate_no_dtd(self):
        """Check for DTD declarations that could enable XXE attacks."""
        xml_str = self.xml_string.decode('utf-8', errors='replace')
        if '<!DOCTYPE' in xml_str.upper() or '<!ENTITY' in xml_str.upper():
            self.errors.append(
                "XML document contains DOCTYPE or ENTITY declarations, "
                "which are not allowed in SAML responses"
            )

    def _validate_root_element(self):
        expected_tag = f'{{{SAML_PROTOCOL_NS}}}Response'
        if self.root.tag != expected_tag:
            self.errors.append(
                f"Root element must be samlp:Response, got {self.root.tag}"
            )

    def _validate_version(self):
        version = self.root.get('Version')
        if version != self.SUPPORTED_VERSION:
            self.errors.append(
                f"Unsupported SAML version: {version}. Expected {self.SUPPORTED_VERSION}"
            )

    def _validate_response_attributes(self):
        for attr in self.REQUIRED_RESPONSE_ATTRIBUTES:
            if not self.root.get(attr):
                self.errors.append(
                    f"Missing required Response attribute: {attr}"
                )

    def _validate_status(self):
        status = self.root.find(f'{{{SAML_PROTOCOL_NS}}}Status')
        if status is None:
            self.errors.append("Missing Status element in Response")
            return

        status_code = status.find(f'{{{SAML_PROTOCOL_NS}}}StatusCode')
        if status_code is None:
            self.errors.append("Missing StatusCode element in Status")
            return

        status_value = status_code.get('Value')
        if status_value != 'urn:oasis:names:tc:SAML:2.0:status:Success':
            status_message_elem = status.find(f'{{{SAML_PROTOCOL_NS}}}StatusMessage')
            status_message = ''
            if status_message_elem is not None and status_message_elem.text:
                status_message = f" Message: {status_message_elem.text}"
            self.errors.append(
                f"SAML Response status is not Success: {status_value}.{status_message}"
            )

    def _validate_assertion_structure(self):
        assertion = self.root.find(f'{{{SAML_ASSERTION_NS}}}Assertion')
        if assertion is None:
            self.errors.append("Missing Assertion element in Response")
            return

        for attr in self.REQUIRED_ASSERTION_ATTRIBUTES:
            if not assertion.get(attr):
                self.errors.append(
                    f"Missing required Assertion attribute: {attr}"
                )

        # Validate Issuer
        issuer = assertion.find(f'{{{SAML_ASSERTION_NS}}}Issuer')
        if issuer is None:
            self.errors.append("Missing Issuer element in Assertion")

        # Validate Subject
        subject = assertion.find(f'{{{SAML_ASSERTION_NS}}}Subject')
        if subject is None:
            self.errors.append("Missing Subject element in Assertion")
        else:
            name_id = subject.find(f'{{{SAML_ASSERTION_NS}}}NameID')
            if name_id is None:
                self.errors.append("Missing NameID element in Subject")

        # Validate Conditions (optional but check structure if present)
        conditions = assertion.find(f'{{{SAML_ASSERTION_NS}}}Conditions')
        if conditions is not None:
            not_before = conditions.get('NotBefore')
            not_on_or_after = conditions.get('NotOnOrAfter')
            if not not_before and not not_on_or_after:
                self.errors.append(
                    "Conditions element should have NotBefore or NotOnOrAfter attributes"
                )

        # Validate AuthnStatement
        authn_statement = assertion.find(f'{{{SAML_ASSERTION_NS}}}AuthnStatement')
        if authn_statement is None:
            self.errors.append("Missing AuthnStatement element in Assertion")


