import base64
import zlib
import xml.etree.ElementTree as ET
from datetime import datetime, timezone
import hashlib
import logging

from .exceptions import SAMLResponseError, SAMLSecurityError
from .xml_validator import (
    SAMLXMLValidator,
    SAML_PROTOCOL_NS,
    SAML_ASSERTION_NS,
    XMLDSIG_NS,
)

logger = logging.getLogger(__name__)


class SAMLResponseParser:
    """Parses SAML POST response and extracts user information."""

    def __init__(self, saml_response_b64, idp_cert=None):
        self.saml_response_b64 = saml_response_b64
        self.idp_cert = idp_cert
        self.xml_string = None
        self.root = None
        self.assertion = None
        self._decoded = False

    def decode_response(self):
        """Decode base64-encoded SAML response."""
        try:
            self.xml_string = base64.b64decode(self.saml_response_b64)
            if isinstance(self.xml_string, bytes):
                # Try to detect if it's deflated
                try:
                    self.xml_string = zlib.decompress(self.xml_string, -15)
                except zlib.error:
                    pass  # Not deflated, use as-is
            self._decoded = True
            return self.xml_string
        except Exception as e:
            raise SAMLResponseError(f"Failed to decode SAML response: {str(e)}")

    def validate_xml(self):
        """Validate the SAML XML structure."""
        if not self._decoded:
            self.decode_response()

        validator = SAMLXMLValidator(self.xml_string)
        is_valid, errors = validator.validate()

        if not is_valid:
            raise SAMLResponseError(
                f"SAML XML validation failed: {'; '.join(errors)}"
            )

        self.root = validator.root
        self.assertion = self.root.find(f'{{{SAML_ASSERTION_NS}}}Assertion')
        return True

    def validate_conditions(self):
        """Validate time-based conditions."""
        if self.assertion is None:
            raise SAMLResponseError("No assertion found to validate conditions")

        conditions = self.assertion.find(f'{{{SAML_ASSERTION_NS}}}Conditions')
        if conditions is None:
            logger.warning("No Conditions element found in assertion")
            return True

        now = datetime.now(timezone.utc)

        not_before = conditions.get('NotBefore')
        if not_before:
            try:
                not_before_dt = datetime.fromisoformat(
                    not_before.replace('Z', '+00:00')
                )
                # Allow 5 minutes clock skew
                from datetime import timedelta
                if now < (not_before_dt - timedelta(minutes=5)):
                    raise SAMLSecurityError(
                        f"SAML assertion is not yet valid. NotBefore: {not_before}"
                    )
            except ValueError as e:
                raise SAMLResponseError(
                    f"Invalid NotBefore datetime format: {not_before}: {e}"
                )

        not_on_or_after = conditions.get('NotOnOrAfter')
        if not_on_or_after:
            try:
                not_on_or_after_dt = datetime.fromisoformat(
                    not_on_or_after.replace('Z', '+00:00')
                )
                from datetime import timedelta
                if now >= (not_on_or_after_dt + timedelta(minutes=5)):
                    raise SAMLSecurityError(
                        f"SAML assertion has expired. NotOnOrAfter: {not_on_or_after}"
                    )
            except ValueError as e:
                raise SAMLResponseError(
                    f"Invalid NotOnOrAfter datetime format: {not_on_or_after}: {e}"
                )

        # Validate AudienceRestriction
        audience_restriction = conditions.find(
            f'{{{SAML_ASSERTION_NS}}}AudienceRestriction'
        )
        if audience_restriction is not None:
            audiences = audience_restriction.findall(
                f'{{{SAML_ASSERTION_NS}}}Audience'
            )
            if audiences:
                from django.conf import settings
                sp_entity_id = getattr(settings, 'SAML_SP_SETTINGS', {}).get(
                    'ENTITY_ID', ''
                )
                audience_values = [a.text for a in audiences if a.text]
                if sp_entity_id and sp_entity_id not in audience_values:
                    raise SAMLSecurityError(
                        f"SP entity ID '{sp_entity_id}' not in audience list: "
                        f"{audience_values}"
                    )

        return True

    def verify_signature(self):
        """
        Verify the XML signature.
        NOTE: For production use, implement proper XML signature verification
        using a library like signxml or xmlsec.
        This is a placeholder that checks signature structure exists.
        """
        if not self.idp_cert:
            logger.warning(
                "No IdP certificate configured - skipping signature verification. "
                "THIS IS NOT SECURE FOR PRODUCTION."
            )
            return True

        # Check if signature exists in response or assertion
        sig_in_response = self.root.find(f'{{{XMLDSIG_NS}}}Signature')
        sig_in_assertion = None
        if self.assertion is not None:
            sig_in_assertion = self.assertion.find(f'{{{XMLDSIG_NS}}}Signature')

        if sig_in_response is None and sig_in_assertion is None:
            raise SAMLSecurityError(
                "No XML signature found in SAML Response or Assertion"
            )

        signature = sig_in_response or sig_in_assertion

        # Verify signature structure
        signed_info = signature.find(f'{{{XMLDSIG_NS}}}SignedInfo')
        if signed_info is None:
            raise SAMLSecurityError("Missing SignedInfo in Signature")

        signature_value = signature.find(f'{{{XMLDSIG_NS}}}SignatureValue')
        if signature_value is None or not signature_value.text:
            raise SAMLSecurityError("Missing or empty SignatureValue")

        key_info = signature.find(f'{{{XMLDSIG_NS}}}KeyInfo')
        if key_info is not None:
            x509_data = key_info.find(f'{{{XMLDSIG_NS}}}X509Data')
            if x509_data is not None:
                x509_cert = x509_data.find(f'{{{XMLDSIG_NS}}}X509Certificate')
                if x509_cert is not None and x509_cert.text:
                    # Compare certificate fingerprints
                    response_cert = x509_cert.text.strip().replace('\n', '').replace(' ', '')
                    configured_cert = self.idp_cert.strip().replace('\n', '').replace(' ', '')
                    # Remove PEM headers if present
                    for header in ['-----BEGIN CERTIFICATE-----', '-----END CERTIFICATE-----']:
                        configured_cert = configured_cert.replace(header, '')

                    response_fingerprint = hashlib.sha256(
                        base64.b64decode(response_cert)
                    ).hexdigest()
                    configured_fingerprint = hashlib.sha256(
                        base64.b64decode(configured_cert)
                    ).hexdigest()

                    if response_fingerprint != configured_fingerprint:
                        raise SAMLSecurityError(
                            "Certificate in SAML response does not match "
                            "configured IdP certificate"
                        )

        logger.info("Signature structure validated (basic check)")
        logger.warning(
            "For production, implement full XML signature verification "
            "using signxml or xmlsec library"
        )
        return True

    def get_name_id(self):
        """Extract NameID from the assertion."""
        if self.assertion is None:
            raise SAMLResponseError("No assertion available")

        subject = self.assertion.find(f'{{{SAML_ASSERTION_NS}}}Subject')
        if subject is None:
            raise SAMLResponseError("No Subject found in assertion")

        name_id_elem = subject.find(f'{{{SAML_ASSERTION_NS}}}NameID')
        if name_id_elem is None or not name_id_elem.text:
            raise SAMLResponseError("No NameID found in Subject")

        return {
            'value': name_id_elem.text.strip(),
            'format': name_id_elem.get('Format', ''),
            'sp_name_qualifier': name_id_elem.get('SPNameQualifier', ''),
            'name_qualifier': name_id_elem.get('NameQualifier', ''),
        }

    def get_issuer(self):
        """Get the Issuer from the assertion."""
        if self.assertion is None:
            raise SAMLResponseError("No assertion available")

        issuer = self.assertion.find(f'{{{SAML_ASSERTION_NS}}}Issuer')
        if issuer is not None and issuer.text:
            return issuer.text.strip()
        return None

    def get_session_index(self):
        """Extract SessionIndex from AuthnStatement."""
        if self.assertion is None:
            return None

        authn_statement = self.assertion.find(
            f'{{{SAML_ASSERTION_NS}}}AuthnStatement'
        )
        if authn_statement is not None:
            return authn_statement.get('SessionIndex')
        return None

    def get_session_expiry(self):
        """Get session expiry from AuthnStatement."""
        if self.assertion is None:
            return None

        authn_statement = self.assertion.find(
            f'{{{SAML_ASSERTION_NS}}}AuthnStatement'
        )
        if authn_statement is not None:
            session_not_on_or_after = authn_statement.get('SessionNotOnOrAfter')
            if session_not_on_or_after:
                try:
                    return datetime.fromisoformat(
                        session_not_on_or_after.replace('Z', '+00:00')
                    )
                except ValueError:
                    pass
        return None

    def get_attributes(self):
        """Extract all attributes from the assertion's AttributeStatement."""
        attributes = {}

        if self.assertion is None:
            return attributes

        attr_statement = self.assertion.find(
            f'{{{SAML_ASSERTION_NS}}}AttributeStatement'
        )
        if attr_statement is None:
            return attributes

        for attribute in attr_statement.findall(
            f'{{{SAML_ASSERTION_NS}}}Attribute'
        ):
            attr_name = attribute.get('Name', '')
            attr_friendly_name = attribute.get('FriendlyName', '')
            attr_values = []

            for attr_value in attribute.findall(
                f'{{{SAML_ASSERTION_NS}}}AttributeValue'
            ):
                if attr_value.text:
                    attr_values.append(attr_value.text.strip())

            # Store by both Name and FriendlyName
            if attr_name:
                attributes[attr_name] = attr_values
            if attr_friendly_name and attr_friendly_name != attr_name:
                attributes[attr_friendly_name] = attr_values

        return attributes

    def get_mapped_attributes(self, attribute_mapping):
        """Map SAML attributes to Django user fields using the configured mapping."""
        raw_attributes = self.get_attributes()
        mapped = {}

        for django_field, saml_names in attribute_mapping.items():
            for saml_name in saml_names:
                if saml_name in raw_attributes and raw_attributes[saml_name]:
                    mapped[django_field] = raw_attributes[saml_name][0]
                    break

        return mapped

    def parse(self):
        """Full parse pipeline: decode, validate, extract."""
        self.decode_response()
        self.validate_xml()
        self.validate_conditions()
        self.verify_signature()

        name_id_info = self.get_name_id()
        attributes = self.get_attributes()
        session_index = self.get_session_index()
        issuer = self.get_issuer()
        session_expiry = self.get_session_expiry()

        return {
            'name_id': name_id_info,
            'issuer': issuer,
            'session_index': session_index,
            'session_expiry': session_expiry,
            'attributes': attributes,
        }


# saml_sp/auth_backend.py
import json
import logging

from django.conf import settings
from django.contrib.auth import get_user_model
from django.contrib.auth.backends import BaseBackend

from .models import SAMLSession

logger = logging.getLogger(__name__)
User = get_user_model()


class SAMLAuthenticationBackend(BaseBackend):
    """Django authentication backend for SAML."""

    def authenticate(self, request, saml_data=None, **kwargs):
        if saml_data is None:
            return None

        name_id_info = saml_data.get('name_id', {})
        name_id = name_id_info.get('value')
        if not name_id:
            logger.error("No NameID in SAML data")
            return None

        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
        attribute_mapping = saml_settings.get('ATTRIBUTE_MAPPING', {})
        create_unknown = saml_settings.get('CREATE_UNKNOWN_USER', True)
        update_on_login = saml_settings.get('UPDATE_USER_ON_LOGIN', True)

        # Map SAML attributes to user fields
        mapped_attrs = self._map_attributes(
            saml_data.get('attributes', {}),
            attribute_mapping
        )

        # Determine username
        username = mapped_attrs.get('username') or name_id
        email = mapped_attrs.get('email', '')

        try:
            # Try to find existing user
            user = self._find_user(username, email, name_id)

            if user is None:
                if create_unknown:
                    user = self._create_user(username, email, mapped_attrs, name_id)
                    logger.info(f"Created new user from SAML: {username}")
                else:
                    logger.warning(
                        f"User not found and CREATE_UNKNOWN_USER is False: {username}"
                    )
                    return None
            elif update_on_login:
                user = self._update_user(user, mapped_attrs)
                logger.info(f"Updated user from SAML: {username}")

            # Create SAML session record
            self._create_saml_session(user, saml_data)

            return user

        except Exception as e:
            logger.exception(f"Error during SAML authentication: {str(e)}")
            return None

    def _map_attributes(self, raw_attributes, attribute_mapping):
        """Map raw SAML attributes to Django user fields."""
        mapped = {}
        for django_field, saml_names in attribute_mapping.items():
            for saml_name in saml_names:
                if saml_name in raw_attributes and raw_attributes[saml_name]:
                    mapped[django_field] = raw_attributes[saml_name][0]
                    break
        return mapped

    def _find_user(self, username, email, name_id):
        """Try to find an existing user by username, email, or NameID."""
        # Try username first
        try:
            return User.objects.get(username=username)
        except User.DoesNotExist:
            pass

        # Try email
        if email:
            try:
                return User.objects.get(email=email)
            except User.DoesNotExist:
                pass
            except User.MultipleObjectsReturned:
                logger.warning(f"Multiple users found with email: {email}")
                return User.objects.filter(email=email).first()

        # Try to find by previous SAML session
        saml_session = SAMLSession.objects.filter(name_id=name_id).first()
        if saml_session:
            return saml_session.user

        return None

    def _create_user(self, username, email, mapped_attrs, name_id):
        """Create a new Django user from SAML attributes."""
        # Ensure username is unique
        original_username = username
        counter = 1
        while User.objects.filter(username=username).exists():
            username = f"{original_username}_{counter}"
            counter += 1

        user = User(
            username=username,
            email=email or f"{username}@saml.local",
            first_name=mapped_attrs.get('first_name', ''),
            last_name=mapped_attrs.get('last_name', ''),
        )
        user.set_unusable_password()
        user.save()

        return user

    def _update_user(self, user, mapped_attrs):
        """Update existing user with SAML attributes."""
        updated = False

        if mapped_attrs.get('email') and user.email != mapped_attrs['email']:
            user.email = mapped_attrs['email']
            updated = True

        if mapped_attrs.get('first_name') and user.first_name != mapped_attrs['first_name']:
            user.first_name = mapped_attrs['first_name']
            updated = True

        if mapped_attrs.get('last_name') and user.last_name != mapped_attrs['last_name']:
            user.last_name = mapped_attrs['last_name']
            updated = True

        if updated:
            user.save()

        return user

    def _create_saml_session(self, user, saml_data):
        """Create a SAML session record."""
        name_id_info = saml_data.get('name_id', {})
        SAMLSession.objects.create(
            user=user,
            name_id=name_id_info.get('value', ''),
            name_id_format=name_id_info.get('format', ''),
            session_index=saml_data.get('session_index', '') or '',
            idp_entity_id=saml_data.get('issuer', '') or '',
            attributes_json=json.dumps(saml_data.get('attributes', {})),
            expires_at=saml_data.get('session_expiry'),
        )

    def get_user(self, user_id):
        try:
            return User.objects.get(pk=user_id)
        except User.DoesNotExist:
            return None


