class SAMLLoginView(View):
    """Initiate SAML login by redirecting to IdP."""

    def get(self, request):
        saml_settings = get_saml_settings()
        idp_sso_url = saml_settings.get('IDP_SSO_URL')
        sp_entity_id = saml_settings.get('ENTITY_ID')
        acs_url = saml_settings.get('ACS_URL')

        if not idp_sso_url:
            return HttpResponseBadRequest("IdP SSO URL not configured")

        # Build AuthnRequest
        request_id = f"_{''.join(str(uuid.uuid4()).split('-'))}"
        issue_instant = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')

        authn_request = f'''<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{idp_sso_url}"
    AssertionConsumerServiceURL="{acs_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{sp_entity_id}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>'''

        import base64
        import zlib

        deflated = zlib.compress(authn_request.encode('utf-8'))[2:-4]
        encoded = base64.b64encode(deflated).decode('utf-8')

        # Store request ID in session for InResponseTo validation
        request.session['saml_request_id'] = request_id
        request.session['saml_relay_state'] = request.GET.get('next', '/')

        params = {
            'SAMLRequest': encoded,
            'RelayState': request.GET.get('next', '/'),
        }

        redirect_url = f"{idp_sso_url}?{urlencode(params)}"
        return HttpResponseRedirect(redirect_url)


@method_decorator(csrf_exempt, name='dispatch')
@method_decorator(never_cache, name='dispatch')
class SAMLACSView(View):
    """Assertion Consumer Service - handles SAML POST responses."""

    def post(self, request):
        saml_response_b64 = request.POST.get('SAMLResponse')
        relay_state = request.POST.get('RelayState', '/')

        if not saml_response_b64:
            logger.error("No SAMLResponse in POST data")
            return HttpResponseBadRequest("Missing SAMLResponse parameter")

        saml_settings = get_saml_settings()
        idp_cert = saml_settings.get('IDP_CERT', '')

        try:
            # Parse and validate the SAML response
            parser = SAMLResponseParser(saml_response_b64, idp_cert=idp_cert)
            saml_data = parser.parse()

            logger.info(
                f"SAML Response parsed successfully. "
                f"NameID: {saml_data['name_id']['value']}, "
                f"Issuer: {saml_data['issuer']}"
            )

            # Validate issuer matches configured IdP
            expected_issuer = saml_settings.get('IDP_ENTITY_ID')
            if expected_issuer and saml_data['issuer'] != expected_issuer:
                raise SAMLSecurityError(
                    f"Unexpected issuer: {saml_data['issuer']}. "
                    f"Expected: {expected_issuer}"
                )

            # Authenticate user using SAML backend
            user = auth.authenticate(request, saml_data=saml_data)

            if user is not None:
                auth.login(request, user)

                # Store SAML info in session
                request.session['saml_name_id'] = saml_data['name_id']['value']
                request.session['saml_name_id_format'] = saml_data['name_id'].get('format', '')
                request.session['saml_session_index'] = saml_data.get('session_index', '')
                request.session['saml_issuer'] = saml_data.get('issuer', '')

                logger.info(f"SAML login successful for user: {user.username}")

                # Redirect to relay state or default
                redirect_url = relay_state if relay_state else '/'
                # Ensure redirect URL is safe
                if not redirect_url.startswith('/'):
                    redirect_url = '/'

                return HttpResponseRedirect(redirect_url)
            else:
                logger.error("SAML authentication failed - no user returned")
                return HttpResponse(
                    "Authentication failed. Could not create or find user.",
                    status=403
                )

        except SAMLSecurityError as e:
            logger.error(f"SAML security error: {str(e)}")
            return HttpResponse(
                f"SAML Security Error: {str(e)}", status=403
            )
        except SAMLError as e:
            logger.error(f"SAML error: {str(e)}")
            return HttpResponseBadRequest(f"SAML Error: {str(e)}")
        except Exception as e:
            logger.exception(f"Unexpected error processing SAML response: {str(e)}")
            return HttpResponse(
                "Internal error processing SAML response", status=500
            )


class SAMLMetadataView(View):
    """Serve SP metadata XML."""

    def get(self, request):
        saml_settings = get_saml_settings()
        entity_id = saml_settings.get('ENTITY_ID', request.build_absolute_uri('/saml/metadata/'))
        acs_url = saml_settings.get('ACS_URL', request.build_absolute_uri('/saml/acs/'))

        metadata = f'''<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{entity_id}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="false"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:persistent</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:transient</md:NameIDFormat>
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{acs_url}"
            index="1"
            isDefault="true"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>'''

        return HttpResponse(metadata, content_type='application/xml')


class SAMLLogoutView(View):
    """Handle SAML logout."""

    def get(self, request):
        # Clear SAML session data
        saml_keys = [
            'saml_name_id', 'saml_name_id_format',
            'saml_session_index', 'saml_issuer',
            'saml_request_id', 'saml_relay_state',
        ]
        for key in saml_keys:
            request.session.pop(key, None)

        auth.logout(request)

        saml_settings = get_saml_settings()
        logout_redirect = saml_settings.get('LOGOUT_REDIRECT_URL', '/')

        return HttpResponseRedirect(logout_redirect)


