import logging
from datetime import datetime, timezone

from django.conf import settings
from django.contrib import auth
from django.http import HttpResponseRedirect
from django.urls import reverse

from .models import SAMLSession

logger = logging.getLogger(__name__)


class SAMLSessionMiddleware:
    """Middleware to validate SAML session is still active."""

    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        if request.user.is_authenticated and request.session.get('saml_name_id'):
            # Check if SAML session has expired
            name_id = request.session.get('saml_name_id')
            session_index = request.session.get('saml_session_index')

            saml_session = SAMLSession.objects.filter(
                name_id=name_id,
                user=request.user,
            ).order_by('-created_at').first()

            if saml_session and saml_session.expires_at:
                if datetime.now(timezone.utc) >= saml_session.expires_at:
                    logger.info(
                        f"SAML session expired for user {request.user.username}"
                    )
                    auth.logout(request)

                    saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
                    login_url = saml_settings.get('LOGIN_URL', '/saml/login/')
                    return HttpResponseRedirect(login_url)

        response = self.get_response(request)
        return response


