# saml_sp/management/commands/cleanup_saml_sessions.py
from datetime import datetime, timezone

from django.core.management.base import BaseCommand

from saml_sp.models import SAMLSession


class Command(BaseCommand):
    help = 'Clean up expired SAML sessions'

    def add_arguments(self, parser):
        parser.add_argument(
            '--days',
            type=int,
            default=30,
            help='Delete sessions older than this many days (default: 30)'
        )

    def handle(self, *args, **options):
        from datetime import timedelta
        cutoff = datetime.now(timezone.utc) - timedelta(days=options['days'])

        count, _ = SAMLSession.objects.filter(created_at__lt=cutoff).delete()
        self.stdout.write(
            self.style.SUCCESS(f'Deleted {count} expired SAML sessions')
        )


