import base64
from datetime import datetime, timezone, timedelta

from django.test import TestCase, RequestFactory, override_settings
from django.contrib.auth import get_user_model

from .response_parser import SAMLResponseParser
from .xml_validator import SAMLXMLValidator
from .auth_backend import SAMLAuthenticationBackend
from .exceptions import SAMLResponseError, SAMLSecurityError, SAMLValidationError
from .models import SAMLSession

User = get_user_model()

SAML_TEST_SETTINGS = {
    'ENTITY_ID': 'https://sp.example.com/saml/metadata/',
    'ACS_URL': 'https://sp.example.com/saml/acs/',
    'IDP_ENTITY_ID': 'https://idp.example.com/',
    'IDP_SSO_URL': 'https://idp.example.com/sso/',
    'IDP_CERT': '',
    'ATTRIBUTE_MAPPING': {
        'email': ['email', 'Email'],
        'first_name': ['firstName', 'givenName'],
        'last_name': ['lastName', 'sn'],
        'username': ['uid', 'Username'],
    },
    'CREATE_UNKNOWN_USER': True,
    'UPDATE_USER_ON_LOGIN': True,
}


def make_saml_response(
    name_id='user@example.com',
    issuer='https://idp.example.com/',
    session_index='_session123',
    attributes=None,
    status='urn:oasis:names:tc:SAML:2.0:status:Success',
    include_conditions=True,
):
    """Helper to build a test SAML response XML."""
    now = datetime.now(timezone.utc)
    not_before = (now - timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    not_on_or_after = (now + timedelta(hours=1)).strftime('%Y-%m-%dT%H:%M:%SZ')
    issue_instant = now.strftime('%Y-%m-%dT%H:%M:%SZ')

    conditions_xml = ''
    if include_conditions:
        conditions_xml = f'''<saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
            <saml:AudienceRestriction>
                <saml:Audience>https://sp.example.com/saml/metadata/</saml:Audience>
            </saml:AudienceRestriction>
        </saml:Conditions>'''

    attr_xml = ''
    if attributes:
        attr_items = ''
        for name, values in attributes.items():
            values_xml = ''.join(
                f'<saml:AttributeValue>{v}</saml:AttributeValue>'
                for v in (values if isinstance(values, list) else [values])
            )
            attr_items += f'''<saml:Attribute Name="{name}">
                {values_xml}
            </saml:Attribute>'''
        attr_xml = f'<saml:AttributeStatement>{attr_items}</saml:AttributeStatement>'

    xml = f'''<samlp:Response
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="_response123"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="https://sp.example.com/saml/acs/">
    <saml:Issuer>{issuer}</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="{status}"/>
    </samlp:Status>
    <saml:Assertion
        ID="_assertion456"
        Version="2.0"
        IssueInstant="{issue_instant}">
        <saml:Issuer>{issuer}</saml:Issuer>
        <saml:Subject>
            <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{name_id}</saml:NameID>
        </saml:Subject>
        {conditions_xml}
        <saml:AuthnStatement AuthnInstant="{issue_instant}" SessionIndex="{session_index}">
            <saml:AuthnContext>
                <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:Password</saml:AuthnContextClassRef>
            </saml:AuthnContext>
        </saml:AuthnStatement>
        {attr_xml}
    </saml:Assertion>
</samlp:Response>'''

    return xml


def encode_saml_response(xml_string):
    """Base64 encode a SAML response for testing."""
    if isinstance(xml_string, str):
        xml_string = xml_string.encode('utf-8')
    return base64.b64encode(xml_string).decode('utf-8')


class SAMLXMLValidatorTest(TestCase):
    def test_valid_response(self):
        xml = make_saml_response()
        validator = SAMLXMLValidator(xml)
        is_valid, errors = validator.validate()
        self.assertTrue(is_valid, f"Errors: {errors}")

    def test_invalid_xml(self):
        validator = SAMLXMLValidator("<not valid xml>><")
        is_valid, errors = validator.validate()
        self.assertFalse(is_valid)

    def test_wrong_root_element(self):
        xml = '<saml:Assertion xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" />'
        validator = SAMLXMLValidator(xml)
        is_valid, errors = validator.validate()
        self.assertFalse(is_valid)
        self.assertTrue(any('Root element' in e for e in errors))

    def test_failed_status(self):
        xml = make_saml_response(
            status='urn:oasis:names:tc:SAML:2.0:status:Requester'
        )
        validator = SAMLXMLValidator(xml)
        is_valid, errors = validator.validate()
        self.assertFalse(is_valid)
        self.assertTrue(any('not Success' in e for e in errors))

    def test_dtd_rejected(self):
        xml = '<!DOCTYPE foo><samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"/>'
        validator = SAMLXMLValidator(xml)
        is_valid, errors = validator.validate()
        self.assertFalse(is_valid)

    def test_oversized_document(self):
        xml = make_saml_response() + ' ' * (600 * 1024)
        validator = SAMLXMLValidator(xml)
        is_valid, errors = validator.validate()
        self.assertFalse(is_valid)
        self.assertTrue(any('maximum size' in e for e in errors))


@override_settings(SAML_SP_SETTINGS=SAML_TEST_SETTINGS)
class SAMLResponseParserTest(TestCase):
    def test_parse_valid_response(self):
        xml = make_saml_response(
            name_id='john@example.com',
            attributes={
                'email': ['john@example.com'],
                'firstName': ['John'],
                'lastName': ['Doe'],
                'uid': ['johndoe'],
            }
        )
        encoded = encode_saml_response(xml)
        parser = SAMLResponseParser(encoded)
        result = parser.parse()

        self.assertEqual(result['name_id']['value'], 'john@example.com')
        self.assertEqual(result['issuer'], 'https://idp.example.com/')
        self.assertEqual(result['session_index'], '_session123')
        self.assertIn('email', result['attributes'])
        self.assertEqual(result['attributes']['email'], ['john@example.com'])

    def test_get_mapped_attributes(self):
        xml = make_saml_response(
            attributes={
                'email': ['jane@example.com'],
                'firstName': ['Jane'],
                'lastName': ['Smith'],
                'uid': ['janesmith'],
            }
        )
        encoded = encode_saml_response(xml)
        parser = SAMLResponseParser(encoded)
        parser.decode_response()
        parser.validate_xml()

        mapped = parser.get_mapped_attributes(
            SAML_TEST_SETTINGS['ATTRIBUTE_MAPPING']
        )

        self.assertEqual(mapped['email'], 'jane@example.com')
        self.assertEqual(mapped['first_name'], 'Jane')
        self.assertEqual(mapped['last_name'], 'Smith')
        self.assertEqual(mapped['username'], 'janesmith')

    def test_invalid_base64(self):
        parser = SAMLResponseParser('!!!not-base64!!!')
        with self.assertRaises(SAMLResponseError):
            parser.decode_response()

    def test_expired_conditions(self):
        now = datetime.now(timezone.utc)
        expired_time = (now - timedelta(hours=2)).strftime('%Y-%m-%dT%H:%M:%SZ')
        really_expired = (now - timedelta(hours=1)).strftime('%Y-%m-%dT%H:%M:%SZ')

        xml = make_saml_response(include_conditions=False)
        # Manually inject expired conditions
        xml = xml.replace(
            '</saml:Subject>',
            f'''</saml:Subject>
            <saml:Conditions NotBefore="{expired_time}" NotOnOrAfter="{really_expired}">
            </saml:Conditions>'''
        )
        encoded = encode_saml_response(xml)
        parser = SAMLResponseParser(encoded)
        parser.decode_response()
        parser.validate_xml()

        with self.assertRaises(SAMLSecurityError):
            parser.validate_conditions()


@override_settings(
    SAML_SP_SETTINGS=SAML_TEST_SETTINGS,
    AUTHENTICATION_BACKENDS=['saml_sp.auth_backend.SAMLAuthenticationBackend']
)
class SAMLAuthBackendTest(TestCase):
    def setUp(self):
        self.factory = RequestFactory()
        self.backend = SAMLAuthenticationBackend()

    def test_create_new_user(self):
        request = self.factory.post('/saml/acs/')
        from django.contrib.sessions.backends.db import SessionStore
        request.session = SessionStore()

        saml_data = {
            'name_id': {
                'value': 'newuser@example.com',
                'format': 'urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress',
            },
            'issuer': 'https://idp.example.com/',
            'session_index': '_sess1',
            'session_expiry': None,
            'attributes': {
                'email': ['newuser@example.com'],
                'firstName': ['New'],
                'lastName': ['User'],
                'uid': ['newuser'],
            },
        }

        user = self.backend.authenticate(request, saml_data=saml_data)

        self.assertIsNotNone(user)
        self.assertEqual(user.username, 'newuser')
        self.assertEqual(user.email, 'newuser@example.com')
        self.assertEqual(user.first_name, 'New')
        self.assertEqual(user.last_name, 'User')
        self.assertFalse(user.has_usable_password())

        # Check SAML session was created
        saml_session = SAMLSession.objects.filter(user=user).first()
        self.assertIsNotNone(saml_session)
        self.assertEqual(saml_session.name_id, 'newuser@example.com')

    def test_existing_user_login(self):
        existing_user = User.objects.create_user(
            username='existinguser',
            email='existing@example.com',
            first_name='Old',
            last_name='Name',
        )

        request = self.factory.post('/saml/acs/')
        from django.contrib.sessions.backends.db import SessionStore
        request.session = SessionStore()

        saml_data = {
            'name_id': {
                'value': 'existing@example.com',
                'format': '',
            },
            'issuer': 'https://idp.example.com/',
            'session_index': '_sess2',
            'session_expiry': None,
            'attributes': {
                'email': ['existing@example.com'],
                'firstName': ['Updated'],
                'lastName': ['Name'],
                'uid': ['existinguser'],
            },
        }

        user = self.backend.authenticate(request, saml_data=saml_data)

        self.assertIsNotNone(user)
        self.assertEqual(user.pk, existing_user.pk)
        self.assertEqual(user.first_name, 'Updated')

    def test_no_saml_data_returns_none(self):
        request = self.factory.post('/saml/acs/')
        user = self.backend.authenticate(request, saml_data=None)
        self.assertIsNone(user)

    @override_settings(SAML_SP_SETTINGS={**SAML_TEST_SETTINGS, 'CREATE_UNKNOWN_USER': False})
    def test_no_create_unknown_user(self):
        request = self.factory.post('/saml/acs/')
        from django.contrib.sessions.backends.db import SessionStore
        request.session = SessionStore()

        saml_data = {
            'name_id': {'value': 'unknown@example.com', 'format': ''},
            'issuer': 'https://idp.example.com/',
            'session_index': '_sess3',
            'session_expiry': None,
            'attributes': {},
        }

        user = self.backend.authenticate(request, saml_data=saml_data)
        self.assertIsNone(user)


@override_settings(SAML_SP_SETTINGS=SAML_TEST_SETTINGS)
class SAMLViewTest(TestCase):
    def test_acs_rejects_get(self):
        response = self.client.get('/saml/acs/')
        self.assertEqual(response.status_code, 405)

    def test_acs_rejects_missing_saml_response(self):
        response = self.client.post('/saml/acs/')
        self.assertEqual(response.status_code, 400)

    def test_acs_processes_valid_response(self):
        xml = make_saml_response(
            name_id='testuser@example.com',
            attributes={
                'email': ['testuser@example.com'],
                'firstName': ['Test'],
                'lastName': ['User'],
                'uid': ['testuser'],
            }
        )
        encoded = encode_saml_response(xml)

        response = self.client.post('/saml/acs/', {
            'SAMLResponse': encoded,
            'RelayState': '/dashboard/',
        })

        # Should redirect on success
        self.assertEqual(response.status_code, 302)
        self.assertEqual(response.url, '/dashboard/')

        # User should be created
        user = User.objects.get(username='testuser')
        self.assertEqual(user.email, 'testuser@example.com')

    def test_metadata_endpoint(self):
        response = self.client.get('/saml/metadata/')
        self.assertEqual(response.status_code, 200)
        self.assertEqual(response['Content-Type'], 'application/xml')
        self.assertIn(b'EntityDescriptor', response.content)
        self.assertIn(b'https://sp.example.com/saml/metadata/', response.content)

    def test_login_redirect(self):
        response = self.client.get('/saml/login/')
        self.assertEqual(response.status_code, 302)
        self.assertIn('idp.example.com', response.url)

    def test_logout(self):
        # Create and login a user first
        user = User.objects.create_user(username='logouttest', password='test')
        self.client.force_login(user)

        session = self.client.session
        session['saml_name_id'] = 'logouttest@example.com'
        session.save()

        response = self.client.get('/saml/logout/')
        self.assertEqual(response.status_code, 302)

    def test_acs_rejects_unsafe_relay_state(self):
        xml = make_saml_response(
            name_id='user@example.com',
            attributes={'uid': ['safeuser']},
        )
        encoded = encode_saml_response(xml)

        response = self.client.post('/saml/acs/', {
            'SAMLResponse': encoded,
            'RelayState': 'https://evil.com/steal',
        })

        # Should redirect to / instead of the evil URL
        self.assertEqual(response.status_code, 302)
        self.assertEqual(response.url, '/')


